using GLMakie
fig = Figure()
ax = Axis(fig[1, 1]; xlabel = "Wavevector", ylabel = "Energy (eV)",
          xticks = path.xticks)
vlines!(ax, path.xticks[1][2:end-1]; color = :gray, linewidth = 0.75)
for b in axes(disp, 1); lines!(ax, disp[b, :]); end
